parameters.jsCode:
// Parse PostHog HogQL response: { results: [[pageviews, dau]], columns: [...], ... }
// On auth/config errors fall back gracefully so we still get a Telegram alert.
const body = $input.first()?.json ?? {};

let pageviews = 0;
let dau = 0;
let errorMsg = '';

const row = body?.results?.[0];
if (Array.isArray(row) && row.length >= 2) {
  pageviews = Number(row[0] ?? 0);
  dau = Number(row[1] ?? 0);
} else if (body?.detail || body?.code || body?.type) {
  errorMsg = `${body.code || body.type || 'error'}: ${body.detail || 'unknown'}`;
}

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('uk-UA', {
  day: 'numeric',
  month: 'long',
  timeZone: 'Europe/Kyiv',
});

return [{ json: { pageviews, dau, dateStr, errorMsg } }];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that builds a stable
// `alertId` so n8n retries no-op via ON CONFLICT DO NOTHING server-side.
const item = $input.first()?.json ?? {};
const alertId = `${$workflow.id || 'wf16'}:${$execution.id || 'unknown'}:posthog-daily`;
const summary = item.errorMsg
  ? `PostHog daily metrics error — ${item.errorMsg}`
  : `PostHog daily — DAU ${Number(item.dau) || 0}, pageviews ${Number(item.pageviews) || 0}.`;
return [{
  json: {
    alertId,
    summary,
    dau: Number(item.dau) || 0,
    pageviews: Number(item.pageviews) || 0,
    dateStr: item.dateStr,
    errorMsg: item.errorMsg,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      dau: Number(item.dau) || 0,
      pageviews: Number(item.pageviews) || 0,
      posthogFailed: Boolean(item.errorMsg),
    },
  },
}];
